function Activity(){
  const [expanded,setExpanded] = useState(null);
  return <div>
    <SectionTitle>Recent Activity</SectionTitle>
    <Divider/>
    <Card>
      <div style={{display:"flex",alignItems:"center",gap:14,cursor:"pointer"}} onClick={()=>setExpanded(expanded==="ben"?null:"ben")}>
        <div style={{width:44,height:44,borderRadius:"50%",background:"linear-gradient(135deg,#2a3f7e,#3a5fae)",border:`2px solid ${G}`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:16,fontWeight:"bold",color:"#fff",flexShrink:0}}>BL</div>
        <div>
          <div style={{color:G,fontWeight:"bold",fontSize:16}}>Ben Lowenthal '76</div>
          <div style={{color:"#ccd",fontSize:13,marginTop:2}}>Click to view profile</div>
        </div>
        <div style={{marginLeft:"auto",color:G,fontSize:18}}>{expanded==="ben"?"▲":"▼"}</div>
      </div>
      {expanded==="ben" && <div style={{marginTop:16,paddingTop:16,borderTop:"1px solid rgba(201,168,76,.2)"}}>
        <p style={{color:"#dde",fontSize:14,lineHeight:1.8}}>
          Ben Lowenthal '76 is a distinguished alumnus of Cincinnati Country Day School.
          Connect with Ben to learn more about his activities and accomplishments since graduation.
        </p>
        <a href="https://www.linkedin.com/in/benlowenthal" target="_blank" rel="noreferrer"
          style={{color:"#7aafff",fontSize:14,textDecoration:"none"}}>View LinkedIn Profile ↗</a>
      </div>}
    </Card>

    <Card style={{padding:0,overflow:"hidden"}}>
      <div style={{display:"flex",alignItems:"center",gap:14,cursor:"pointer",padding:"18px 22px"}}
        onClick={()=>setExpanded(expanded==="jeff"?null:"jeff")}>
        <img src={IMG_JEFF} alt="Jeffrey W. Harrison"
          style={{width:52,height:52,borderRadius:"50%",objectFit:"cover",objectPosition:"top",border:`2px solid ${G}`,flexShrink:0}}/>
        <div>
          <div style={{color:G,fontWeight:"bold",fontSize:16}}>Jeffrey W. Harrison '76</div>
          <div style={{color:"#ccd",fontSize:13,marginTop:2}}>Award-winning poet · Author of six collections</div>
        </div>
        <div style={{marginLeft:"auto",color:G,fontSize:18,paddingRight:4}}>{expanded==="jeff"?"▲":"▼"}</div>
      </div>
      {expanded==="jeff" && <div style={{padding:"0 22px 20px"}}>
        <div style={{display:"flex",gap:18,alignItems:"flex-start",marginBottom:14}}>
          <img src={IMG_JEFF} alt="Jeffrey W. Harrison"
            style={{width:120,borderRadius:8,border:`2px solid ${G}`,flexShrink:0,objectFit:"cover",objectPosition:"top center",maxHeight:150}}/>
          <div style={{color:"#dde",fontSize:14,lineHeight:1.8}}>
            <p style={{margin:"0 0 10px"}}>
              Jeff is a successful, award-winning poet and the author of six full-length books of poetry,
              including <em>Between Lakes</em> (2020), selected as a 2021 Must-Read Book by the Massachusetts
              Center for the Book; <em>Into Daylight</em> (2014), winner of the Dorset Prize;
              <em> Incomplete Knowledge</em> (2006); <em>Feeding the Fire</em> (2001), which won the Sheila Motton
              Award from the New England Poetry Club; and <em>The Singing Underneath</em>, selected by James Merrill
              for the National Poetry Series in 1987.
            </p>
          </div>
        </div>
        <p style={{color:"#dde",fontSize:14,lineHeight:1.8,margin:"0 0 10px"}}>
          A volume of his selected early poems, <em>The Names of Things</em>, was published in the U.K. in 2006.
          He has received fellowships from the Guggenheim Foundation and the National Endowment for the Arts,
          among other honors. His poems have appeared widely in <em>The New Republic</em>, <em>The New Yorker</em>,
          <em>The Paris Review</em>, and other literary journals, as well as in Best American Poetry, The Pushcart
          Prize volumes, Poets of the New Century, and The Twentieth Century in Poetry.
        </p>
        <p style={{color:"#dde",fontSize:14,lineHeight:1.8,margin:"0 0 10px"}}>
          He has been featured regularly in Ted Kooser's <em>American Life in Poetry</em> and Garrison Keillor's
          radio show <em>The Writer's Almanac</em>. He has taught at a number of colleges and universities,
          as well as at Phillips Academy, where he was Writer-in-Residence, and has visited many high schools
          to read his work and discuss poetry with students. He lives in Massachusetts.
        </p>
        <p style={{color:"#dde",fontSize:14,lineHeight:1.8,margin:0}}>
          Jeff has remained an active alumnus, is a loyal supporter of the Country Day Fund, and has been
          back to present to our students many times over the years.
        </p>
      </div>}
    </Card>
  </div>;
}

