function Archive({loggedIn,user}){
  const [items,setItems] = useState([{
    id:1, title:"Senior Day",
    by:"Site Administrator",
    taken:"May 1976",
    sortKey:197605,
    caption:"Students going through the outdoor buffet line during CCDS Senior Day, May 1976.",
    src:IMG_SENIOR, type:"photo", posted:"2026-03-03"
  }]);
  const [show,setShow] = useState(false);
  const [form,setForm] = useState({title:"",caption:"",month:"",src:null,preview:null});
  const fileRef = useRef();

  function fmtMonth(m){
    if(!m) return "Unknown date";
    const [y,mo] = m.split("-");
    const months=["Jan","Feb","Mar","Apr","May","Jun","Jul","Aug","Sep","Oct","Nov","Dec"];
    return `${months[parseInt(mo)-1]} ${y}`;
  }

  function submit(){
    if(!form.title.trim()){alert("Please add a title.");return;}
    const sk = form.month ? parseInt(form.month.replace("-","").slice(0,6)) : 999999;
    const nd = {
      id:Date.now(), title:form.title.trim(),
      by: user||"Member",
      taken: form.month ? fmtMonth(form.month) : "Unknown date",
      sortKey:sk,
      caption:form.caption.trim(),
      src:form.src, type:"photo",
      posted:new Date().toISOString().slice(0,10)
    };
    setItems(p=>[...p,nd].sort((a,b)=>a.sortKey-b.sortKey));
    setForm({title:"",caption:"",month:"",src:null,preview:null});
    setShow(false);
  }

  return <div>
    <SectionTitle>Digital Archive</SectionTitle>
    <Divider/>
    <p style={{color:"#ccd",fontSize:14,marginBottom:16}}>
      A shared repository of photographs and articles from our years at CCDS and beyond.
      Items are displayed in <strong style={{color:G}}>chronological order</strong> by when the photo was taken
      or the article was written.
    </p>
    {loggedIn && <button onClick={()=>setShow(s=>!s)}
      style={{background:show?"#444":G,color:show?"#eee":N,border:"none",borderRadius:6,
              padding:"10px 20px",fontWeight:"bold",fontSize:14,cursor:"pointer",marginBottom:20}}>
      {show?"✕ Cancel":"＋ Add to Archive"}
    </button>}
    {!loggedIn && <p style={{color:"#aab",fontSize:13,fontStyle:"italic",marginBottom:16}}>Log in to contribute photos and articles.</p>}
    {show && loggedIn && <Card style={{background:"rgba(26,42,94,.7)",marginBottom:24}}>
      <h3 style={{color:G,marginTop:0,fontFamily:"Georgia,serif"}}>Add New Item</h3>
      <div style={{display:"flex",flexDirection:"column",gap:12}}>
        <div><label style={lS}>Title *</label>
          <input style={iS} value={form.title} onChange={e=>setForm(p=>({...p,title:e.target.value}))} placeholder="e.g. Graduation Day 1976"/></div>
        <div><label style={lS}>Date Taken / Written</label>
          <input style={iS} type="month" value={form.month} onChange={e=>setForm(p=>({...p,month:e.target.value}))}/>
          <span style={{color:"#aab",fontSize:12,marginLeft:8}}>Leave blank if unknown</span></div>
        <div><label style={lS}>Caption</label>
          <textarea style={{...iS,minHeight:70,resize:"vertical"}} value={form.caption}
            onChange={e=>setForm(p=>({...p,caption:e.target.value}))} placeholder="Describe the photo or article..."/></div>
        <div><label style={lS}>Upload Image</label>
          <input ref={fileRef} type="file" accept="image/*" style={{color:"#eef",fontSize:14}}
            onChange={e=>{const f=e.target.files[0];if(!f)return;const r=new FileReader();
              r.onload=ev=>setForm(p=>({...p,src:ev.target.result,preview:ev.target.result}));
              r.readAsDataURL(f);}}/>
          {form.preview && <img src={form.preview} alt="preview"
            style={{marginTop:10,maxWidth:"100%",maxHeight:200,borderRadius:6,border:`1px solid ${G}`}}/>}
        </div>
        <button onClick={submit}
          style={{background:G,color:N,border:"none",borderRadius:6,padding:"10px 20px",
                  fontWeight:"bold",fontSize:14,cursor:"pointer",alignSelf:"flex-start"}}>
          Submit to Archive
        </button>
      </div>
    </Card>}
    {[...items].sort((a,b)=>a.sortKey-b.sortKey).map(it=><div key={it.id}
      style={{background:"rgba(255,255,255,.06)",border:"1px solid rgba(201,168,76,.25)",
              borderRadius:10,marginBottom:20,overflow:"hidden"}}>
      {it.src
        ? <img src={it.src} alt={it.title} style={{width:"100%",maxHeight:400,objectFit:"cover",display:"block"}}/>
        : <div style={{background:"rgba(0,0,0,.3)",height:100,display:"flex",alignItems:"center",justifyContent:"center",color:"#556",fontSize:36}}>🖼</div>}
      <div style={{padding:"14px 18px"}}>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",flexWrap:"wrap",gap:6}}>
          <h3 style={{color:"#eef",margin:0,fontFamily:"Georgia,serif",fontSize:17}}>{it.title}</h3>
          <span style={{background:G,color:N,fontSize:11,fontWeight:"bold",borderRadius:20,padding:"2px 10px",whiteSpace:"nowrap"}}>{it.taken}</span>
        </div>
        {it.caption && <p style={{color:"#ccd",fontSize:14,marginTop:8,marginBottom:4,lineHeight:1.6}}>{it.caption}</p>}
        <div style={{color:"#778",fontSize:12,marginTop:8}}>
          Posted by <strong style={{color:"#aab"}}>{it.by}</strong> · {it.posted}
        </div>
      </div>
    </div>)}
  </div>;
}

function AuthModal({onLogin,onClose}){
  const [mode,setMode] = useState("login");
  const [form,setForm] = useState({name:"",email:"",password:""});
  const users = [
    {name:"Site Administrator",email:"admin@ccds1976.org",password:"admin"},
    {name:"Michael Barach",email:"mbarach@example.com",password:"ccds1976"},
    {name:"Jeff Harrison",email:"jharrison@example.com",password:"ccds1976"},
    {name:"Keith Kerman",email:"kkerman76@example.com",password:"ccds1976"},
  ];
  function go(){
    if(mode==="login"){
      const u=users.find(u=>u.email===form.email&&u.password===form.password);
      if(u){onLogin(u.name);onClose();}
      else alert("Invalid credentials. Demo: admin@ccds1976.org / admin");
    } else {
      if(!form.name||!form.email||!form.password){alert("Please fill all fields.");return;}
      onLogin(form.name);onClose();
    }
  }
  return <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,.75)",display:"flex",alignItems:"center",justifyContent:"center",zIndex:1000}} onClick={onClose}>
    <div onClick={e=>e.stopPropagation()} style={{background:N,border:`2px solid ${G}`,borderRadius:12,padding:32,width:340,maxWidth:"90vw"}}>
      <h2 style={{color:G,fontFamily:"Georgia,serif",marginTop:0}}>{mode==="login"?"Log In":"Create Account"}</h2>
      {mode==="register"&&<div style={{marginBottom:14}}><label style={lS}>Full Name</label><input style={iS} value={form.name} onChange={e=>setForm(p=>({...p,name:e.target.value}))}/></div>}
      <div style={{marginBottom:14}}><label style={lS}>Email</label><input style={iS} type="email" value={form.email} onChange={e=>setForm(p=>({...p,email:e.target.value}))}/></div>
      <div style={{marginBottom:20}}><label style={lS}>Password</label><input style={iS} type="password" value={form.password} onChange={e=>setForm(p=>({...p,password:e.target.value}))}/></div>
      <button onClick={go} style={{width:"100%",background:G,color:N,border:"none",borderRadius:6,padding:"11px 0",fontWeight:"bold",fontSize:15,cursor:"pointer"}}>{mode==="login"?"Log In":"Register"}</button>
      <p style={{color:"#aab",fontSize:13,textAlign:"center",marginTop:14}}>
        {mode==="login"
          ?<>Don't have an account? <span onClick={()=>setMode("register")} style={{color:G,cursor:"pointer"}}>Register</span></>
          :<>Already registered? <span onClick={()=>setMode("login")} style={{color:G,cursor:"pointer"}}>Log In</span></>}
      </p>
    </div>
  </div>;
}

const TABS = [
  {id:"home",     l:"Home"},
  {id:"c76",      l:"Class of 1976"},
  {id:"sched",    l:"Reunion Schedule"},
  {id:"archive",  l:"Digital Archive"},
  {id:"activity", l:"Recent Activity"},
  {id:"attending",l:"Attending Reunion"},
  {id:"memoriam", l:"In Memoriam"},
];

export default function CCDS1976(){
  const [tab,setTab]           = useState("home");
  const [loggedIn,setLoggedIn] = useState(false);
  const [user,setUser]         = useState(null);
  const [showAuth,setShowAuth] = useState(false);

  return <div style={{minHeight:"100vh",background:"linear-gradient(160deg,#0e1a3d 0%,#1a2a5e 50%,#0e1a3d 100%)",color:"#eef",fontFamily:"Arial,sans-serif"}}>
    <div style={{background:"linear-gradient(90deg,#1a2a5e,#0e1a3d)",borderBottom:`3px solid ${G}`,padding:"20px 24px",display:"flex",alignItems:"center",justifyContent:"space-between",flexWrap:"wrap",gap:12}}>
      <div>
        <div style={{fontSize:11,color:G,letterSpacing:3,textTransform:"uppercase",marginBottom:2}}>Cincinnati Country Day School</div>
        <h1 style={{margin:0,fontFamily:"Georgia,serif",fontSize:26,color:"#fff",lineHeight:1.1}}>Class of 1976</h1>
        <div style={{fontSize:12,color:"#aab",marginTop:2}}>50th Reunion · September 2026</div>
      </div>
      <div style={{display:"flex",alignItems:"center",gap:10}}>
        {loggedIn
          ?<><span style={{color:G,fontSize:13}}>👤 {user}</span>
            <button onClick={()=>{setLoggedIn(false);setUser(null);}} style={{background:"transparent",border:`1px solid ${G}`,color:G,borderRadius:6,padding:"6px 14px",cursor:"pointer",fontSize:13}}>Log Out</button></>
          :<button onClick={()=>setShowAuth(true)} style={{background:G,color:N,border:"none",borderRadius:6,padding:"8px 18px",cursor:"pointer",fontWeight:"bold",fontSize:13}}>Log In</button>}
      </div>
    </div>
    <div style={{background:"rgba(0,0,0,.3)",borderBottom:"1px solid rgba(201,168,76,.2)",padding:"10px 24px",display:"flex",flexWrap:"wrap",gap:8}}>
      {TABS.map(t=><button key={t.id} onClick={()=>setTab(t.id)}
        style={{background:tab===t.id?G:"transparent",color:tab===t.id?N:"#dde",
                border:`1px solid ${tab===t.id?G:"rgba(201,168,76,.3)"}`,
                borderRadius:6,padding:"7px 14px",cursor:"pointer",fontSize:13,
                fontWeight:tab===t.id?"bold":"normal",whiteSpace:"nowrap"}}>
        {t.l}
      </button>)}
    </div>
    <div style={{maxWidth:760,margin:"0 auto",padding:"32px 20px"}}>
      {tab==="home"     && <Home/>}
      {tab==="c76"      && <C76/>}
      {tab==="sched"    && <Sched/>}
      {tab==="archive"  && <Archive loggedIn={loggedIn} user={user}/>}
      {tab==="activity" && <Activity/>}
      {tab==="attending"&& <Attending/>}
      {tab==="memoriam" && <Memoriam/>}
    </div>
    <div style={{textAlign:"center",padding:"24px 20px",borderTop:"1px solid rgba(201,168,76,.15)",color:"#556"}}>
      <div style={{color:G,fontFamily:"Georgia,serif",fontSize:14,marginBottom:4}}>CCDS Class of 1976</div>
      <div style={{fontSize:12}}>ccds1976.org · 6905 Given Road, Cincinnati OH 45243</div>
    </div>
    {showAuth && <AuthModal onLogin={n=>{setLoggedIn(true);setUser(n);}} onClose={()=>setShowAuth(false)}/>}
  </div>;
}
